### QueryClient Cache Management Methods

Source: https://context7.com/tanstack/query/llms.txt

Shows various QueryClient methods for programmatic cache control including prefetching, optimistic updates, invalidation, cancellation, retrieving cached data, and cache clearing operations.

```typescript
import { useQueryClient } from '@tanstack/react-query'

function CacheManagement() {
  const queryClient = useQueryClient()

  // Prefetch data before navigation
  const prefetchPost = async (postId: number) => {
    await queryClient.prefetchQuery({
      queryKey: ['post', postId],
      queryFn: () => fetch(`/api/posts/${postId}`).then(r => r.json()),
      staleTime: 1000 * 60,
    })
  }

  // Manually set query data
  const optimisticUpdate = (postId: number, updates: Partial<Post>) => {
    queryClient.setQueryData(['post', postId], (old: Post | undefined) => {
      if (!old) return old
      return { ...old, ...updates }
    })
  }

  // Invalidate queries to trigger refetch
  const refreshPosts = async () => {
    await queryClient.invalidateQueries({
      queryKey: ['posts'],
      refetchType: 'active', // Only refetch active queries
    })
  }

  // Cancel ongoing queries
  const cancelPostsQuery = async () => {
    await queryClient.cancelQueries({ queryKey: ['posts'] })
  }

  // Get cached data
  const getCachedPost = (postId: number) => {
    return queryClient.getQueryData<Post>(['post', postId])
  }

  // Remove queries from cache
  const clearCache = () => {
    queryClient.removeQueries({ queryKey: ['posts'] })
  }

  // Reset queries (clear cache and refetch)
  const resetQueries = async () => {
    await queryClient.resetQueries({ queryKey: ['posts'] })
  }

  return (
    <div>
      <button onClick={refreshPosts}>Refresh Posts</button>
      <button onClick={() => prefetchPost(42)}>Prefetch Post #42</button>
      <button onClick={clearCache}>Clear Cache</button>
    </div>
  )
}
```

